/* ================================================================== */
/*  CLAUDE CODE — QUESTION GENERATION INSTRUCTIONS                     */
/*                                                                      */
/*  This file contains the custom trivia question bank for Fourth &    */
/*  Down. Questions are embedded into the server bundle at build time   */
/*  by build-exe.mjs (it reads this file and evals the customQuestions */
/*  object).                                                            */
/*                                                                      */
/*  TO GENERATE MORE QUESTIONS:                                         */
/*  1. Read this file to see existing questions and avoid duplicates    */
/*  2. Count current questions per category (run the node -e script     */
/*     shown below)                                                     */
/*  3. APPEND new questions to the END of each category array           */
/*  4. Use this exact format per question:                              */
/*     { question: 'text', correct_answer: 'answer',                   */
/*       wrong_answers: ['w1', 'w2', 'w3'],                            */
/*       category: 'Display Name', difficulty: 'easy'|'medium'|'hard' }*/
/*  5. Wrong answers must be plausible (not obviously wrong)            */
/*  6. Questions should be fun for drunk friends at a party             */
/*  7. Difficulty split target: ~35% easy, ~40% medium, ~25% hard      */
/*  8. After editing, run: npx tsc --noEmit && node build-exe.mjs      */
/*                                                                      */
/*  COUNT SCRIPT (run from project root):                               */
/*    node scripts/count-trivia.js                                      */
/*    (or ask Claude to count questions per category)                    */
/*                                                                      */
/*  CATEGORIES:                                                         */
/*    custom-nfc-north   — Packers, Bears, Vikings, Lions, NFC North   */
/*    custom-classic-rock — 60s-80s rock bands, albums, concerts        */
/*    custom-90s-rap      — Golden age hip-hop, artists, albums, feuds  */
/*    custom-sports       — All sports: NFL, NBA, MLB, NHL, Olympics    */
/*    custom-movies-tv    — Movies, TV shows, actors, directors         */
/*    custom-general      — Geography, science, history, pop culture    */
/*    custom-food-drink   — Cocktails, spirits, beer, food, bar culture */
/*                                                                      */
/*  SOURCE TRACKING:                                                    */
/*    Questions from this file are tagged source:"ai" in the server.    */
/*    OpenTDB API questions are tagged source:"api".                    */
/*    Future custom questions from the trivia_questions DB table        */
/*    will be tagged source:"custom".                                   */
/*    Add a `source` field to individual questions to override          */
/*    (e.g. source: 'custom' for hand-written questions).               */
/*                                                                      */
/*  LAST GENERATED: 2026-03-24 by Claude Code                          */
/*  QUESTION COUNT AT LAST GEN: ~1050 (target was 150 per category)    */
/* ================================================================== */

export interface TriviaQuestion {
  question: string;
  correct_answer: string;
  wrong_answers: string[];
  category: string;
  difficulty: 'easy' | 'medium' | 'hard';
}

export interface TriviaCategory {
  id: string;
  name: string;
  icon: string;
  /** Open Trivia DB category ID, or null for custom */
  otdbId: number | null;
  color: string;
}

