/* ---- Helper to get shuffled questions from a custom category ---- */

export function getCustomQuestions(
  categoryId: string,
  count: number,
  difficulty?: 'easy' | 'medium' | 'hard',
): TriviaQuestion[] {
  const bank = customQuestions[categoryId] ?? [];
  let filtered = difficulty ? bank.filter((q) => q.difficulty === difficulty) : [...bank];
  // Shuffle
  for (let i = filtered.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [filtered[i], filtered[j]] = [filtered[j], filtered[i]];
  }
  return filtered.slice(0, count);
}
